import{_ as a,C as u,c as l,o as s,j as n,G as r,ag as o,a as t}from"./chunks/framework.qANVs27k.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","pageClass":"page-services","hero":{"name":false,"text":"Dienstleistungen","tagline":"Von Setup und Hosting über Datenmigration bis zu Betrieb, Schulung und individueller Weiterentwicklung","image":{"src":"/images/qonnectra_logo.png","alt":"Qonnectra Logo"},"actions":[{"theme":"brand","text":"Kontakt aufnehmen","link":"/contact/"}]},"features":[{"title":"1. Kostenfreie Präsentation","details":"Lernen Sie Qonnectra unverbindlich kennen, online oder vor Ort. Wir zeigen die Software in einer persönlichen Live-Demo und gehen auf Ihre Anwendungsfälle und Fragen ein."},{"title":"2. Setup und Hosting","details":"Wir richten Qonnectra für Sie ein, auf Ihrer Infrastruktur oder in einer passenden Hosting-Umgebung. Dazu gehören Installation, Konfiguration und die betriebsbereite Übergabe."},{"title":"3. Datenmigration","details":"Wir analysieren Ihre Netzdokumentation und übernehmen die strukturierte Aufbereitung und Migration nach Qonnectra. Dabei berücksichtigen wir GIS, CAD Daten, Tabellen und weitere Quellen."},{"title":"4. Betrieb und Systembetreuung","details":"Wir übernehmen den Betrieb und die Betreuung Ihrer Qonnectra Umgebung. Dazu gehören Support, Fehleranalyse, Nutzerverwaltung und Backups."},{"title":"5. Fortführung der Netzdokumentation","details":"Wir unterstützen die Pflege und Weiterentwicklung Ihrer Netzdokumentation, zum Beispiel bei Netzauskünften, Exporten und der Dokumentation von Erweiterungen."},{"title":"6. Schulungen und Weiterbildung","details":"Wir schulen Anwender und Verantwortliche im Umgang mit Qonnectra und bieten ergänzende Schulungen zu Netzdokumentation und QGIS an."}]},"headers":[],"relativePath":"services/index.md","filePath":"services/index.md"}'),d={name:"services/index.md"};function h(g,e,c,m,b,f){const i=u("VPButton");return s(),l("div",null,[e[0]||(e[0]=n("p",null,"Wir begleiten Sie bei der Einführung und dem Betrieb von Qonnectra von Anfang an. Von der ersten Vorstellung über die technische Einrichtung und Datenmigration bis hin zum laufenden Betrieb, der Pflege Ihrer Netzdokumentation und gezielten Schulungen stehen wir Ihnen verlässlich zur Seite.",-1)),e[1]||(e[1]=n("p",null,"Die folgenden Leistungen zeigen die einzelnen Schritte entlang dieses Prozesses und geben Ihnen einen Überblick darüber, wie wir Sie in jeder Phase unterstützen.",-1)),e[2]||(e[2]=n("h2",{id:"_1-kostenfreie-prasentation",tabindex:"-1"},[t("1. Kostenfreie Präsentation "),n("a",{class:"header-anchor",href:"#_1-kostenfreie-prasentation","aria-label":'Permalink to "1. Kostenfreie Präsentation"'},"​")],-1)),e[3]||(e[3]=n("p",null,[t("Sie möchten Qonnectra kennenlernen oder prüfen, wie sich Ihre bestehende Netzdokumentation in Qonnectra überführen lässt? Wir zeigen Ihnen die Software gerne in einer "),n("strong",null,"kostenfreien persönlichen Präsentation"),t(" und besprechen mit Ihnen passende nächste Schritte.")],-1)),r(i,{href:"/contact/",text:"Präsentation anfragen"}),e[4]||(e[4]=o('<h2 id="_2-setup-und-hosting" tabindex="-1">2. Setup und Hosting <a class="header-anchor" href="#_2-setup-und-hosting" aria-label="Permalink to &quot;2. Setup und Hosting&quot;">​</a></h2><p>Wir übernehmen die technische Einrichtung von Qonnectra und schaffen die Grundlage für einen stabilen produktiven Betrieb. Diese Leistung eignet sich für Organisationen, die Qonnectra schnell und sauber in Betrieb nehmen möchten.</p><details class="details custom-block" open=""><summary>Typische Leistungen</summary><ul><li>Installation aller benötigten Open-Source-Komponenten</li><li>Einrichtung auf kundeneigener Infrastruktur oder in einer Hosting-Umgebung</li><li>Grundkonfiguration von Rollen, Rechten und Projektstrukturen</li><li>Einrichtung von Bauteilen, Nomenklaturen und Basisparametern</li><li>Übergabe eines einsatzbereiten Systems</li></ul></details><h2 id="_3-datenmigration" tabindex="-1">3. Datenmigration <a class="header-anchor" href="#_3-datenmigration" aria-label="Permalink to &quot;3. Datenmigration&quot;">​</a></h2><p>Der Wechsel auf eine neue Plattform ist nur dann erfolgreich, wenn auch bestehende Daten sinnvoll übernommen werden können. Deshalb unterstützen wir Sie bei der Sichtung, Bewertung und Migration Ihrer vorhandenen Netzdokumentation. So entsteht eine belastbare Datengrundlage für den weiteren Betrieb.</p><details class="details custom-block" open=""><summary>Typische Leistungen</summary><ul><li>Analyse vorhandener Datenbestände</li><li>Bewertung der Datenqualität und Importfähigkeit</li><li>Abstimmung, welche Inhalte übernommen werden sollen</li><li>Aufbereitung von Geometrien, Topologien und Fachlogiken</li><li>Entwicklung eines tragfähigen Dokumentationskonzepts</li><li>Vollständiger Import der Bestandsdaten in Qonnectra</li></ul></details><details class="details custom-block"><summary>Mögliche Datenquellen</summary><ul><li>GIS-Daten</li><li>CAD-Daten</li><li>CSV- und Tabellendaten</li><li>bestehende Dokumentationssysteme</li><li>weitere strukturierte oder teilstrukturierte Datenbestände</li></ul></details><h2 id="_4-betrieb-und-systembetreuung" tabindex="-1">4. Betrieb und Systembetreuung <a class="header-anchor" href="#_4-betrieb-und-systembetreuung" aria-label="Permalink to &quot;4. Betrieb und Systembetreuung&quot;">​</a></h2><p>Auch nach der Einführung unterstützen wir Sie beim zuverlässigen Betrieb Ihrer Qonnectra-Umgebung. Je nach Bedarf kann die Betreuung projektbezogen, stundenweise oder im Rahmen einer dauerhaften Vereinbarung erfolgen.</p><details class="details custom-block" open=""><summary>Leistungen im laufenden Betrieb:</summary><ul><li>Betreuung der Qonnectra-Systemkomponenten</li><li>Unterstützung bei Fehlermeldungen und Störungen</li><li>Nutzer- und Rechteverwaltung</li><li>Backup-Konzepte und organisatorische Betriebssicherheit</li><li>Nachvollziehbarkeit und Begleitung von Änderungen an Datenbeständen</li><li>persönliche Unterstützung im Rahmen von Support und Hotline</li></ul></details><h2 id="_5-fortfuhrung-der-netzdokumentation" tabindex="-1">5. Fortführung der Netzdokumentation <a class="header-anchor" href="#_5-fortfuhrung-der-netzdokumentation" aria-label="Permalink to &quot;5. Fortführung der Netzdokumentation&quot;">​</a></h2><p>Auf Wunsch unterstützen wir Sie nicht nur technisch, sondern auch fachlich bei der laufenden Pflege Ihrer Netzdokumentation. Damit bleibt Ihre Dokumentation aktuell, konsistent und nutzbar.</p><details class="details custom-block" open=""><summary>Beispiele</summary><ul><li>Fortführung von Netzerweiterungen und Neubauten</li><li>Erstellung von Netzauskünften</li><li>Export von Daten für interne oder externe Zwecke</li><li>kartographische Visualisierungen</li><li>Unterstützung bei dokumentationsbezogenen Anfragen Dritter</li></ul></details><h2 id="_6-schulungen-und-weiterbildung" tabindex="-1">6. Schulungen und Weiterbildung <a class="header-anchor" href="#_6-schulungen-und-weiterbildung" aria-label="Permalink to &quot;6. Schulungen und Weiterbildung&quot;">​</a></h2><p>Damit Ihr Team sicher mit Qonnectra arbeiten kann, bieten wir praxisnahe Schulungen für unterschiedliche Zielgruppen an. Das <a href="/Qonnectra-docs/branch-main/manual/">Softwarehandbuch</a> steht kostenfrei zur Verfügung. Ergänzend helfen Schulungen dabei, Prozesse schneller und sicherer in die Praxis zu überführen.</p><details class="details custom-block" open=""><summary>Mögliche Formate</summary><ul><li>Qonnectra-Grundlagenschulungen</li><li>rollenbasierte Schulungen für Planung, Dokumentation und Administration</li><li>Schulungen zu einzelnen Workflows</li><li>Grundlagen der Netzdokumentation</li><li>QGIS-Schulungen</li><li>QGIS im Zusammenspiel mit Qonnectra</li></ul></details><h2 id="individuelle-erweiterungen" tabindex="-1">Individuelle Erweiterungen <a class="header-anchor" href="#individuelle-erweiterungen" aria-label="Permalink to &quot;Individuelle Erweiterungen&quot;">​</a></h2><p>Qonnectra kann an spezifische Anforderungen angepasst und funktional erweitert werden. Wir entwickeln bei Bedarf zusätzliche Features, Schnittstellen oder Workflows, die über die Standardfunktionen hinausgehen. So lässt sich Qonnectra passgenau in bestehende Prozesse integrieren.</p><details class="details custom-block"><summary>Beispiele für individuelle Leistungen</summary><ul><li>zusätzliche Softwarefunktionen</li><li>projektspezifische Workflows</li><li>Schnittstellen zu Drittsystemen</li><li>fachliche Erweiterungen für besondere Anforderungen</li></ul></details><h2 id="fur-wen-sich-unsere-dienstleistungen-eignen" tabindex="-1">Für wen sich unsere Dienstleistungen eignen <a class="header-anchor" href="#fur-wen-sich-unsere-dienstleistungen-eignen" aria-label="Permalink to &quot;Für wen sich unsere Dienstleistungen eignen&quot;">​</a></h2><p>Unsere Dienstleistungen richten sich an Organisationen, die Qonnectra professionell einführen, bestehende Daten übernehmen oder den Betrieb dauerhaft absichern möchten.</p><p>Besonders relevant sind unsere Leistungen für:</p><ul><li>Netzbetreiber</li><li>Planungs- und Ingenieurbüros</li><li>kommunale und regionale Infrastrukturakteure</li><li>Organisationen mit gewachsenen Bestandsdaten und Migrationsbedarf</li></ul>',23)),r(i,{href:"/contact/",text:"Kontakt aufnehmen"})])}const z=a(d,[["render",h]]);export{p as __pageData,z as default};
